sys_script.script:
// Copyrights belong to Discover Technologies LLC. © 2019 Discover Technologies LLC
// Script Continued Below
(function executeRule(current, previous /*null when async*/) {
	// RJ - PSD - STRY0063760 - Copy Shared Documents from Task Tree to Process
	if (!current.original_tasker_inst.nil() ) {
		var grTask = new GlideRecord('x_153465_discovert_route_task_instance');
		if(grTask.get(current.getValue("original_tasker_inst"))){
			var fromConfigId = gs.getProperty("x_153465_discovert.DocIntViewSysIDTasks");
			var toConfigId = gs.getProperty("x_153465_discovert.DocIntProcessTaskViewSysIDTasks");
			var tDS = new taskerDocumentScripts();
			tDS.copyDocuments (grTask, current, 'My', fromConfigId, toConfigId);
			// RJ - PSD - STRY0063760 - now copy attachments from tree to process
			tDS.copyAttachments(grTask, current, 'My');
		}
	}
})(current, previous);
